import React, { useState, useEffect, useRef } from 'react';

export default function Combobox({ options, placeholder = '' }) {
  const [query, setQuery] = useState('');
  const [open, setOpen] = useState(false);
  const [value, setValue] = useState(null);
  const [active, setActive] = useState(0);
  const root = useRef(null);

  useEffect(() => {
    const onDoc = (e) => {
      if (root.current && !root.current.contains(e.target)) {
        setOpen(false);
        setQuery(value ? value.label : '');
      }
    };
    document.addEventListener('mousedown', onDoc);
    return () => document.removeEventListener('mousedown', onDoc);
  }, [value]);

  const filtered =
    open && query && (!value || query !== value.label)
      ? options.filter((o) => o.label.toLowerCase().includes(query.toLowerCase()))
      : options;

  const select = (o) => {
    setValue(o);
    setQuery(o.label);
    setOpen(false);
  };

  const clear = () => {
    setValue(null);
    setQuery('');
    setActive(0);
  };

  const onKeyDown = (e) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setOpen(true);
      setActive((a) => Math.min(a + 1, filtered.length - 1));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setActive((a) => Math.max(a - 1, 0));
    } else if (e.key === 'Enter' && open && filtered[active]) {
      select(filtered[active]);
    } else if (e.key === 'Escape') {
      setOpen(false);
    }
  };

  return (
    <div ref={root} style={{ position: 'relative', width: 280 }}>
      <div style={{ display: 'flex', border: '1px solid #ccc', borderRadius: 8, overflow: 'hidden' }}>
        <input
          role="combobox"
          aria-expanded={open}
          value={query}
          placeholder={placeholder}
          onChange={(e) => {
            setQuery(e.target.value);
            setOpen(true);
            setActive(0);
          }}
          onFocus={() => setOpen(true)}
          onKeyDown={onKeyDown}
          style={{ flex: 1, padding: 10, border: 'none', outline: 'none', fontSize: 15 }}
        />
        {value && (
          <button onClick={clear} aria-label="Clear" style={{ border: 'none', background: 'none', cursor: 'pointer', padding: '0 10px' }}>✕</button>
        )}
      </div>

      {open && (
        <ul role="listbox" style={{ position: 'absolute', top: '100%', left: 0, right: 0, margin: '4px 0 0', padding: 4, listStyle: 'none', border: '1px solid #ddd', borderRadius: 8, background: '#fff', boxShadow: '0 6px 20px rgba(0,0,0,0.12)', maxHeight: 220, overflowY: 'auto', zIndex: 10 }}>
          {filtered.map((o, i) => (
            <li
              key={o.value}
              role="option"
              aria-selected={value && value.value === o.value}
              onMouseDown={(e) => {
                e.preventDefault();
                select(o);
              }}
              onMouseEnter={() => setActive(i)}
              style={{ padding: '8px 10px', cursor: 'pointer', borderRadius: 6, background: i === active ? '#eef2ff' : '#fff', fontWeight: value && value.value === o.value ? 700 : 400 }}
            >
              {o.label}
            </li>
          ))}
          {filtered.length === 0 && <li style={{ padding: '8px 10px', color: '#aaa' }}>No matches</li>}
        </ul>
      )}
    </div>
  );
}

