import { Component, Input, HostListener, ElementRef } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Option { value: string; label: string; }

@Component({
  selector: 'app-combobox',
  template: `
    <div style="position: relative; width: 280px;">
      <div style="display: flex; border: 1px solid #ccc; border-radius: 8px; overflow: hidden;">
        <input
          role="combobox"
          [attr.aria-expanded]="open"
          [value]="query"
          [placeholder]="placeholder"
          (input)="onInput($any($event.target).value)"
          (focus)="open = true"
          (keydown.arrowdown)="$event.preventDefault(); move(1)"
          (keydown.arrowup)="$event.preventDefault(); move(-1)"
          (keydown.enter)="onEnter()"
          (keydown.escape)="open = false"
          style="flex: 1; padding: 10px; border: none; outline: none; font-size: 15px;"
        />
        <button *ngIf="value" (click)="clear()" aria-label="Clear" style="border: none; background: none; cursor: pointer; padding: 0 10px;">✕</button>
      </div>

      <ul
        *ngIf="open"
        role="listbox"
        style="position: absolute; top: 100%; left: 0; right: 0; margin: 4px 0 0; padding: 4px; list-style: none; border: 1px solid #ddd; border-radius: 8px; background: #fff; box-shadow: 0 6px 20px rgba(0,0,0,0.12); max-height: 220px; overflow-y: auto; z-index: 10;"
      >
        <li
          *ngFor="let o of filtered; let i = index"
          role="option"
          [attr.aria-selected]="value && value.value === o.value"
          (mousedown)="$event.preventDefault(); select(o)"
          (mouseenter)="active = i"
          [style.background]="i === active ? '#eef2ff' : '#fff'"
          [style.font-weight]="value && value.value === o.value ? 700 : 400"
          style="padding: 8px 10px; cursor: pointer; border-radius: 6px;"
        >{{ o.label }}</li>
        <li *ngIf="filtered.length === 0" style="padding: 8px 10px; color: #aaa;">No matches</li>
      </ul>
    </div>
  `,
})
export class ComboboxComponent {
  @Input() options: Option[] = [];
  @Input() placeholder = '';
  query = '';
  open = false;
  value: Option | null = null;
  active = 0;

  constructor(private host: ElementRef<HTMLElement>) {}

  get filtered(): Option[] {
    const typing = this.open && this.query && (!this.value || this.query !== this.value.label);
    if (!typing) {
      return this.options;
    }
    const q = this.query.toLowerCase();
    return this.options.filter((o) => o.label.toLowerCase().indexOf(q) !== -1);
  }

  onInput(value: string): void {
    this.query = value;
    this.open = true;
    this.active = 0;
  }

  move(delta: number): void {
    this.open = true;
    const next = this.active + delta;
    this.active = Math.max(0, Math.min(next, this.filtered.length - 1));
  }

  onEnter(): void {
    if (this.open && this.filtered[this.active]) {
      this.select(this.filtered[this.active]);
    }
  }

  select(o: Option): void {
    this.value = o;
    this.query = o.label;
    this.open = false;
  }

  clear(): void {
    this.value = null;
    this.query = '';
    this.active = 0;
  }

  @HostListener('document:click', ['$event'])
  onDoc(e: MouseEvent): void {
    if (!this.host.nativeElement.contains(e.target as Node)) {
      this.open = false;
      this.query = this.value ? this.value.label : '';
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Combobox Demo</h1>
      <app-combobox [options]="options" placeholder="Choose a country…"></app-combobox>
    </div>
  `,
})
export class AppComponent {
  options: Option[] = [
    { value: 'us', label: 'United States' },
    { value: 'ca', label: 'Canada' },
    { value: 'mx', label: 'Mexico' },
    { value: 'br', label: 'Brazil' },
    { value: 'gb', label: 'United Kingdom' },
    { value: 'de', label: 'Germany' },
    { value: 'fr', label: 'France' },
    { value: 'jp', label: 'Japan' },
  ];
}

@NgModule({
  declarations: [AppComponent, ComboboxComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
